import hashlib
def hashFile(fileName):
    try:
        f = open(fileName, 'rb')
        hsh = hashlib.sha1()
        byte = f.read(8096)
        while len(byte)> 0:
            hsh.update(byte)
            byte=f.read(8096)
        return hsh.hexdigest()
    except IOError as e:
        raise